<template>
  <div id="centerRight1">
    <div class="bg-color-black">
      <div class="d-flex pt-2 pl-2">
        <span>
          <icon name="chart-line" class="text-icon"></icon>
        </span>
        <div class="d-flex">
          <span class="fs-xl text mx-2">边缘节点状态</span>
        </div>
      </div>
      <div class="device-info">
        <div class="device-card">
          <div class="device-header">
            <span class="device-status" :class="isConnected ? 'online' : 'offline'"></span>
            <span class="device-name">设备-001</span>
            <span class="connection-tag" :class="isConnected ? 'connected' : 'disconnected'">
              {{ isConnected ? '已连接' : '已断开' }}
            </span>
          </div>
          <div class="device-details">
            <div class="detail-item">
              <span class="label">设备状态</span>
              <span class="value" :class="isConnected ? 'online' : 'offline'">
                {{ isConnected ? '运行中' : '离线' }}
              </span>
            </div>
            <div class="detail-item">
              <span class="label">数据来源</span>
              <span class="value">边缘计算节点(深圳)</span>
            </div>
            <div class="detail-item">
              <span class="label">同步状态</span>
              <span class="value" :class="isConnected ? 'sync' : 'offline'">
                {{ isConnected ? '实时同步' : '同步中断' }}
              </span>
            </div>
            <div class="detail-item">
              <span class="label">最后更新</span>
              <span class="value" :class="{ 'warning': secondsSinceUpdate > 5, 'offline': !isConnected }">
                {{ lastUpdate }}
              </span>
            </div>
          </div>
        </div>
        <div class="data-flow">
          <div class="flow-item">
            <div class="flow-icon device">📡</div>
            <div class="flow-label">设备采集</div>
          </div>
          <div class="flow-arrow-container">
            <div class="flow-dot" :style="{ animationDelay: '0s' }"></div>
            <div class="flow-dot" :style="{ animationDelay: '0.3s' }"></div>
            <div class="flow-dot" :style="{ animationDelay: '0.6s' }"></div>
          </div>
          <div class="flow-item">
            <div class="flow-icon edge">⚡</div>
            <div class="flow-label">边缘计算</div>
          </div>
          <div class="flow-arrow-container">
            <div class="flow-dot" :style="{ animationDelay: '0.9s' }"></div>
            <div class="flow-dot" :style="{ animationDelay: '1.2s' }"></div>
            <div class="flow-dot" :style="{ animationDelay: '1.5s' }"></div>
          </div>
          <div class="flow-item">
            <div class="flow-icon cloud">☁️</div>
            <div class="flow-label">云端存储</div>
          </div>
        </div>
        <div class="data-stats">
          <div class="stat-item">
            <span class="stat-value">{{ dataPackets }}</span>
            <span class="stat-label">数据包/秒</span>
          </div>
          <div class="stat-item">
            <span class="stat-value">{{ dataSize }}KB</span>
            <span class="stat-label">传输量</span>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { mapState } from 'vuex'

export default {
  data() {
    return {
      dataPackets: 0,
      dataSize: 0,
      updateTimer: null
    }
  },
  computed: {
    ...mapState(['edgeConnected', 'lastDataTime']),
    isConnected() {
      return this.edgeConnected
    },
    lastUpdate() {
      if (!this.lastDataTime) {
        return this.edgeConnected ? '刚刚' : '无数据'
      }
      const seconds = Math.floor((new Date() - new Date(this.lastDataTime)) / 1000)
      if (seconds <= 2) {
        return '刚刚'
      } else if (seconds < 60) {
        return `${seconds}秒前`
      } else {
        return `${Math.floor(seconds / 60)}分钟前`
      }
    }
  },
  mounted() {
    this.startDataStatsTimer()
  },
  beforeDestroy() {
    if (this.updateTimer) clearInterval(this.updateTimer)
  },
  methods: {
    startDataStatsTimer() {
      // 每秒更新数据包统计和最后更新时间
      this.updateTimer = setInterval(() => {
        if (this.isConnected) {
          this.dataPackets = Math.floor(120 + Math.random() * 20)
          this.dataSize = (2 + Math.random() * 1).toFixed(1)
        } else {
          this.dataPackets = 0
          this.dataSize = 0
        }
        // 强制更新lastUpdate计算属性
        this.$forceUpdate()
      }, 1000)
    }
  }
}
</script>

<style lang="scss" scoped>
$box-height: 410px;
#centerRight1 {
  padding: 16px;
  padding-top: 20px;
  height: $box-height;
  width: 100%;
  border-radius: 5px;
  .bg-color-black {
    height: $box-height - 30px;
    border-radius: 10px;
  }
  .text {
    color: #c3cbde;
  }
  
  .device-info {
    padding: 15px;
  }
  
  .device-card {
    background: linear-gradient(135deg, #1a2a4a 0%, #0d1b2a 100%);
    border: 1px solid #2a4a6a;
    border-radius: 10px;
    padding: 15px;
    margin-bottom: 15px;
  }
  
  .device-header {
    display: flex;
    align-items: center;
    margin-bottom: 15px;
    padding-bottom: 10px;
    border-bottom: 1px solid #2a4a6a;
  }
  
  .device-status {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    margin-right: 10px;
    
    &.online {
      background: #00ff88;
      box-shadow: 0 0 10px #00ff88;
      animation: pulse 2s infinite;
    }
    
    &.offline {
      background: #ff4757;
      box-shadow: 0 0 10px #ff4757;
      animation: none;
    }
  }
  
  .device-name {
    color: #fff;
    font-size: 16px;
    font-weight: bold;
    flex: 1;
  }
  
  .connection-tag {
    font-size: 10px;
    padding: 2px 8px;
    border-radius: 10px;
    
    &.connected {
      background: rgba(0, 255, 136, 0.2);
      color: #00ff88;
      border: 1px solid #00ff88;
    }
    
    &.disconnected {
      background: rgba(255, 71, 87, 0.2);
      color: #ff4757;
      border: 1px solid #ff4757;
    }
  }
  
  .device-details {
    .detail-item {
      display: flex;
      justify-content: space-between;
      padding: 8px 0;
      border-bottom: 1px dashed #2a4a6a;
      
      &:last-child {
        border-bottom: none;
      }
    }
    
    .label {
      color: #8899aa;
      font-size: 13px;
    }
    
    .value {
      color: #c3cbde;
      font-size: 13px;
      
      &.online {
        color: #00ff88;
      }
      
      &.offline {
        color: #ff4757;
      }
      
      &.sync {
        color: #4a90e2;
      }
      
      &.warning {
        color: #ffa502;
      }
    }
  }
  
  .data-flow {
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: #0d1b2a;
    border-radius: 8px;
    padding: 15px 10px;
  }
  
  .flow-item {
    text-align: center;
  }
  
  .flow-icon {
    font-size: 24px;
    margin-bottom: 5px;
  }
  
  .flow-label {
    color: #8899aa;
    font-size: 11px;
  }
  
  .flow-arrow-container {
    display: flex;
    align-items: center;
    gap: 4px;
    padding: 0 5px;
  }
  
  .flow-dot {
    width: 6px;
    height: 6px;
    background: #4a90e2;
    border-radius: 50%;
    animation: flowMove 2s infinite;
  }
  
  .data-stats {
    display: flex;
    justify-content: space-around;
    margin-top: 10px;
    padding: 10px;
    background: #0d1b2a;
    border-radius: 6px;
  }
  
  .stat-item {
    text-align: center;
  }
  
  .stat-value {
    display: block;
    color: #00ff88;
    font-size: 16px;
    font-weight: bold;
  }
  
  .stat-label {
    color: #8899aa;
    font-size: 10px;
  }
  
  @keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.5; }
  }
  
  @keyframes flowMove {
    0% { 
      opacity: 0.2;
      transform: scale(0.8);
    }
    50% { 
      opacity: 1;
      transform: scale(1.2);
      box-shadow: 0 0 8px #4a90e2;
    }
    100% { 
      opacity: 0.2;
      transform: scale(0.8);
    }
  }
}
</style>
