<template>
  <div>
    <div v-if="loading" class="loading-container">
      <div class="loading-spinner"></div>
      <span class="loading-text">数据加载中...</span>
    </div>
    <div v-else-if="error" class="error-container">
      <span class="error-text">数据加载失败</span>
      <button @click="loadData" class="retry-btn">重试</button>
    </div>
    <Chart v-else :cdata="cdata" />
  </div>
</template>

<script>
import Chart from './chart.vue';
import { API_ENDPOINTS } from '@/config';
export default {
  data () {
    return {
      loading: true,
      error: false,
      updateTimer: null,
      cdata: {
        xData: ["设备运行", "数据采集", "质量检测", "能耗监控", "故障预警", "维护管理"],
        seriesData: [
          { value: 28, name: "设备运行" },
          { value: 22, name: "数据采集" },
          { value: 18, name: "质量检测" },
          { value: 15, name: "能耗监控" },
          { value: 10, name: "故障预警" },
          { value: 7, name: "维护管理" }
        ]
      }
    }
  },
  components: {
    Chart,
  },
  mounted () {
    this.loadData();
    this.startUpdateTimer();
  },
  beforeDestroy() {
    if (this.updateTimer) {
      clearInterval(this.updateTimer);
    }
  },
  methods: {
    async loadData() {
      try {
        this.loading = true;
        this.error = false;
        
        const response = await fetch(API_ENDPOINTS.INDUSTRIAL_PIE_DATA);
        const data = await response.json();
        
        this.cdata.xData = data.xData;
        this.cdata.seriesData = data.seriesData;
        
        this.loading = false;
      } catch (error) {
        console.error('数据加载失败:', error);
        this.error = true;
        this.loading = false;
      }
    },
    startUpdateTimer() {
      this.updateTimer = setInterval(() => {
        this.loadData();
      }, 50000); // 每秒更新一次
    }
  }
}
</script>

