<template>
  <div>
    <div v-if="loading" class="loading-container">
      <div class="loading-spinner"></div>
      <span class="loading-text">数据加载中...</span>
    </div>
    <div v-else-if="error" class="error-container">
      <span class="error-text">数据加载失败</span>
      <button @click="loadData" class="retry-btn">重试</button>
    </div>
    <Chart v-else :cdata="cdata" />
  </div>
</template>

<script>
import Chart from './chart.vue'
import { API_ENDPOINTS } from '@/config'
import { mapState } from 'vuex'

const VIBRATION_THRESHOLD = 16
const NOISE_THRESHOLD = 90
const TEMPERATURE_THRESHOLD = 5

export default {
  data () {
    return {
      loading: true,
      error: false,
      drawTiming: null,
      cdata: {
        year: null,
        weekCategory: [],
        radarData: [],
        radarDataAvg: [],
        maxData: 100,
        weekMaxData: [],
        weekLineData: []
      }
    }
  },
  components: {
    Chart
  },
  computed: {
    ...mapState(['edgeConnected'])
  },
  mounted () {
    this.loadData()
    this.drawTimingFn()
  },
  beforeDestroy () {
    clearInterval(this.drawTiming)
  },
  methods: {
    processDataset (data) {
      if (!Array.isArray(data)) return
      const now = new Date()
      this.cdata.year = now.getFullYear()
      this.cdata.weekCategory = data.map(item => item.date)
      this.cdata.weekLineData = data.map(item => {
        const ratio = item.noise_ratio ?? (item.noise ? item.noise / NOISE_THRESHOLD : 0)
        return Math.round(Math.min(ratio, 1) * this.cdata.maxData)
      })
      this.cdata.weekMaxData = data.map(() => this.cdata.maxData)
        this.cdata.radarData = data.map(item => [
        +(item.x_vibration_ratio ?? (item.x_vibration / VIBRATION_THRESHOLD)).toFixed(3),
        +(item.z_vibration_ratio ?? (item.z_vibration / VIBRATION_THRESHOLD)).toFixed(3),
        +(item.noise_ratio ?? (item.noise / NOISE_THRESHOLD)).toFixed(3),
        +(item.temperature_ratio ?? ((item.temperature || 0) / TEMPERATURE_THRESHOLD)).toFixed(3)
      ])
      this.cdata.radarDataAvg = data.map(() => [1, 1, 1, 1])
    },
    async loadData () {
      try {
        this.loading = true
        this.error = false
        const response = await fetch(API_ENDPOINTS.VIBRATION)
        const data = await response.json()
        this.processDataset(data)
        this.loading = false
      } catch (error) {
        console.error('数据加载失败:', error)
        this.error = true
        this.loading = false
      }
    },
    drawTimingFn () {
      this.setData()
      this.drawTiming = setInterval(() => {
        this.setData()
      }, 1000)
    },
    async setData () {
      // 设备离线时不更新数据，保持静止
      if (!this.edgeConnected) {
        return
      }
      try {
        const response = await fetch(API_ENDPOINTS.REALTIME_VIBRATION)
        const data = await response.json()
        this.processDataset(data)
      } catch (error) {
        console.error('获取实时数据失败:', error)
        // 离线时不生成假数据
      }
    },
    generateLocalData () {
      this.cdata.weekCategory = []
      this.cdata.weekMaxData = []
      this.cdata.weekLineData = []
      this.cdata.radarData = []
      this.cdata.radarDataAvg = []

      const now = new Date()
      this.cdata.year = now.getFullYear()
      for (let i = 0; i < 7; i++) {
        const date = new Date()
        date.setDate(date.getDate() - (6 - i))
        this.cdata.weekCategory.push([date.getMonth() + 1, date.getDate()].join('/'))
        const noise = Math.random() * NOISE_THRESHOLD
        this.cdata.weekMaxData.push(this.cdata.maxData)
        this.cdata.weekLineData.push(Math.round((noise / NOISE_THRESHOLD) * this.cdata.maxData))
        const xVibration = Math.random() * (VIBRATION_THRESHOLD * 0.6) + 2
        const zVibration = Math.random() * (VIBRATION_THRESHOLD * 0.6) + 3
        const temperature = Math.random() * 2 + 1
        this.cdata.radarData.push([
          +(xVibration / VIBRATION_THRESHOLD).toFixed(3),
          +(zVibration / VIBRATION_THRESHOLD).toFixed(3),
          +(noise / NOISE_THRESHOLD).toFixed(3),
          +(temperature / TEMPERATURE_THRESHOLD).toFixed(3)
        ])
        this.cdata.radarDataAvg.push([1, 1, 1, 1])
      }
    }
  }
}
</script>

<style lang="scss" scoped>
