<template>
  <div id="centerLeft1">
    <div class="bg-color-black">
      <div class="d-flex pt-2 pl-2">
        <span>
          <icon name="chart-bar" class="text-icon"></icon>
        </span>
        <div class="d-flex">
          <span class="fs-xl text mx-2">设备状态监控</span>
          <dv-decoration-3 class="dv-dec-3" />
        </div>
      </div>
      <div class="d-flex jc-center">
        <CenterLeft1Chart />
      </div>
      <!-- 4个主要的数据 -->
      <div class="bottom-data">
        <div v-if="loading" class="loading-container">
          <div class="loading-spinner"></div>
          <span class="loading-text">数据加载中...</span>
        </div>
        <div v-else-if="error" class="error-container">
          <span class="error-text">数据加载失败</span>
          <button @click="loadData" class="retry-btn">重试</button>
        </div>
        <div
          v-else
          class="item-box mt-2"
          v-for="(item, index) in numberData"
          :key="index"
        >
          <div class="d-flex">
            <dv-digital-flop class="dv-digital-flop" :config="item.number" />
          </div>
          <p class="text" style="text-align: center;">
            {{ item.text }}
            <span class="colorYellow">({{ item.unit }})</span>
          </p>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import CenterLeft1Chart from '@/components/echart/centerLeft/centerLeft1Chart'
import { API_ENDPOINTS } from '@/config'
import { mapState } from 'vuex'

export default {
  data() {
    return {
      loading: true,
      error: false,
      numberData: [
        {
          number: {
            number: [0],
            toFixed: 0,
            textAlign: 'left',
            content: '{nt}',
            style: {
              fontSize: 24
            }
          },
          text: '在线设备',
          unit: '台/共5台'
        },
        {
          number: {
            number: [0],
            toFixed: 1,
            textAlign: 'left',
            content: '{nt}',
            style: {
              fontSize: 24
            }
          },
          text: '累计运行时长',
          unit: '小时'
        },
        {
          number: {
            number: [0],
            toFixed: 0,
            textAlign: 'left',
            content: '{nt}',
            style: {
              fontSize: 24
            }
          },
          text: '维护次数',
          unit: '次'
        },
        {
          number: {
            number: [0],
            toFixed: 0,
            textAlign: 'left',
            content: '{nt}',
            style: {
              fontSize: 24
            }
          },
          text: '离线设备',
          unit: '台'
        }
      ]
    }
  },
  components: {
    CenterLeft1Chart
  },
  computed: {
    ...mapState(['edgeConnected'])
  },
  watch: {
    // 监听连接状态变化，更新在线设备数
    edgeConnected(connected) {
      if (connected) {
        this.numberData[0].number.number[0] = 1
        this.numberData[3].number.number[0] = 4
      } else {
        this.numberData[0].number.number[0] = 0
        this.numberData[3].number.number[0] = 5
      }
      this.numberData = [...this.numberData]
    }
  },
  mounted() {
    this.loadData()
    this.changeTiming()
  },
  methods: {
    async loadData() {
      try {
        this.loading = true
        this.error = false
        
        const response = await fetch(API_ENDPOINTS.DEVICE_STATUS)
        const data = await response.json()
        
        // 根据连接状态决定在线设备数
        if (this.edgeConnected) {
          this.numberData[0].number.number[0] = data.online_count || 1
          this.numberData[3].number.number[0] = data.standby_count || 4
        } else {
          this.numberData[0].number.number[0] = 0
          this.numberData[3].number.number[0] = 5  // 全部离线
        }
        this.numberData[1].number.number[0] = data.running_hours
        this.numberData[2].number.number[0] = data.maintenance_count
        
        // 重新触发数字翻牌器更新
        this.numberData = [...this.numberData]
        
        this.loading = false
      } catch (error) {
        console.error('数据加载失败:', error)
        this.error = true
        this.loading = false
      }
    },
    changeTiming() {
      setInterval(() => {
        this.loadData()
      }, 10000)
    }
  }
}
</script>

