<template>
  <div>
    <div v-if="loading" class="loading-container">
      <div class="loading-spinner"></div>
      <span class="loading-text">数据加载中...</span>
    </div>
    <div v-else-if="error" class="error-container">
      <span class="error-text">数据加载失败</span>
      <button @click="loadData" class="retry-btn">重试</button>
    </div>
    <Chart v-else :cdata="cdata" />
  </div>
</template>

<script>
import Chart from './chart.vue'
import { API_ENDPOINTS } from '@/config'
export default {
  data () {
    return {
      loading: true,
      error: false,
      cdata: {
        category: [],
        lineData: [],
        barData: [],
        rateData: []
      },
      refreshTimer: null
    };
  },
  components: {
    Chart,
  },
  mounted () {
    this.loadData();
    this.startAutoRefresh();
  },
  beforeDestroy() {
    if (this.refreshTimer) {
      clearInterval(this.refreshTimer);
    }
  },
  methods: {
    async loadData() {
      try {
        this.loading = true;
        this.error = false;
        
        const response = await fetch(API_ENDPOINTS.PRODUCTION_DAILY);
        const data = await response.json();
        
        this.cdata.category = data.map(item => item.date);
        this.cdata.lineData = data.map(item => item.total_production);
        this.cdata.barData = data.map(item => item.quality_products);
        this.cdata.rateData = data.map(item => item.quality_rate);
        
        this.loading = false;
      } catch (error) {
        console.error('数据加载失败:', error);
        this.error = true;
        this.loading = false;
      }
    },
    startAutoRefresh() {
      // 每30秒刷新一次数据
      this.refreshTimer = setInterval(() => {
        this.loadData();
      }, 30000);
    }
  }
};
</script>

<style lang="scss" scoped>
.loading-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 200px;
  .loading-spinner {
    width: 30px;
    height: 30px;
    border: 3px solid #333;
    border-top: 3px solid #00bcd4;
    border-radius: 50%;
    animation: spin 1s linear infinite;
    margin-bottom: 10px;
  }
  .loading-text {
    font-size: 14px;
    color: #888;
  }
}
.error-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 200px;
  .error-text {
    font-size: 14px;
    color: #ff6b6b;
    margin-bottom: 10px;
  }
  .retry-btn {
    background: #ff6b6b;
    color: white;
    border: none;
    padding: 6px 12px;
    border-radius: 4px;
    font-size: 12px;
    cursor: pointer;
    &:hover {
      background: #ff5252;
    }
  }
}
@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}
</style>