<template>
  <div id="center">
    <div class="up">
      <div
        class="bg-color-black item"
        v-for="item in titleItem"
        :key="item.title"
      >
        <p class="ml-3 colorBlue fw-b fs-xl">{{ item.title }}</p>
        <div v-if="loading" class="loading-container">
          <div class="loading-spinner"></div>
          <span class="loading-text">数据加载中...</span>
        </div>
        <div v-else-if="error" class="error-container">
          <span class="error-text">数据加载失败</span>
          <button @click="loadData" class="retry-btn">重试</button>
        </div>
        <div v-else>
          <dv-digital-flop
            class="dv-dig-flop ml-1 mt-2 pl-3"
            :config="item.number"
          />
        </div>
        <div class="data-description">
          <span class="description-text">{{ item.description }}</span>
        </div>
      </div>
    </div>
    <div class="down">
      <div class="ranking bg-color-black">
        <span>
          <icon name="chart-pie" class="text-icon"></icon>
        </span>
        <span class="fs-xl text mx-2 mb-1 pl-3">工件批次良率</span>
        <dv-scroll-ranking-board class="dv-scr-rank-board mt-1" :config="ranking" />
      </div>
      <div class="percent">
        <div class="item bg-color-black">
          <span>设备运行率</span>
          <CenterChart
            :id="rate[0].id"
            :tips="rate[0].tips"
            :colorObj="rate[0].colorData"
          />
        </div>
        <div class="item bg-color-black">
          <span>质量合格率</span>
          <CenterChart
            :id="rate[1].id"
            :tips="rate[1].tips"
            :colorObj="rate[1].colorData"
          />
        </div>
        <div class="water">
          <dv-water-level-pond class="dv-wa-le-po" :config="water" />
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import CenterChart from '@/components/echart/center/centerChartRate'
import { API_ENDPOINTS } from '@/config'
import { mapState } from 'vuex'

export default {
  data() {
    return {
      loading: true,
      error: false,
      titleItem: [
        {
          title: '今日总产量',
          description: '当日生产的所有产品数量',
          number: {
            number: [0],
            toFixed: 0,
            textAlign: 'left',
            content: '{nt}件',
            style: {
              fontSize: 26
            }
          }
        },
        {
          title: '今日良品量',
          description: '符合质量标准的合格产品数量',
          number: {
            number: [0],
            toFixed: 0,
            textAlign: 'left',
            content: '{nt}件',
            style: {
              fontSize: 26
            }
          }
        },
        {
          title: '今日良品率',
          description: '良品数量占总产量的百分比',
          number: {
            number: [0],
            toFixed: 1,
            textAlign: 'left',
            content: '{nt}%',
            style: {
              fontSize: 26
            }
          }
        },
        {
          title: '设备运行率',
          description: '设备实际运行时间占计划运行时间的比例',
          number: {
            number: [0],
            toFixed: 1,
            textAlign: 'left',
            content: '{nt}%',
            style: {
              fontSize: 26
            }
          }
        },
        {
          title: '能耗效率',
          description: '单位产品能耗与标准能耗的比值',
          number: {
            number: [0],
            toFixed: 1,
            textAlign: 'left',
            content: '{nt}%',
            style: {
              fontSize: 26
            }
          }
        },
        {
          title: '在线设备',
          description: '当前在线设备数/总设备数',
          number: {
            number: [0],
            toFixed: 0,
            textAlign: 'left',
            content: '{nt}/5台',
            style: {
              fontSize: 26
            }
          }
        }
      ],
      ranking: {
        data: [],
        carousel: 'single',
        unit: '%'
      },
      water: {
        data: [87, 95],
        shape: 'roundRect',
        formatter: '{value}%',
        waveNum: 3
      },
      // 设备运行率和质量合格率的组件复用数据
      rate: [
        {
          id: 'centerRate1',
          tips: 87,
          colorData: {
            textStyle: '#3fc0fb',
            series: {
              color: ['#00bcd44a', 'transparent'],
              dataColor: {
                normal: '#03a9f4',
                shadowColor: '#97e2f5'
              }
            }
          }
        },
        {
          id: 'centerRate2',
          tips: 95,
          colorData: {
            textStyle: '#67e0e3',
            series: {
              color: ['#faf3a378', 'transparent'],
              dataColor: {
                normal: '#ff9800',
                shadowColor: '#fcebad'
              }
            }
          }
        }
      ]
    }
  },
  components: {
    CenterChart
  },
  computed: {
    ...mapState(['edgeConnected'])
  },
  mounted() {
    this.loadData()
    this.startAutoRefresh()
  },
  beforeDestroy() {
    if (this.refreshTimer) {
      clearInterval(this.refreshTimer)
    }
  },
  methods: {
    startAutoRefresh() {
      // 每5秒刷新一次数据
      this.refreshTimer = setInterval(() => {
        this.loadData()
      }, 5000)
    },
    async loadData() {
      try {
        this.loading = this.titleItem[0].number.number[0] === 0
        this.error = false
        
        // 获取生产数据
        const productionResponse = await fetch(API_ENDPOINTS.PRODUCTION)
        const productionData = await productionResponse.json()
        
        // 获取设备数据
        const equipmentResponse = await fetch(API_ENDPOINTS.EQUIPMENT)
        const equipmentData = await equipmentResponse.json()
        
        // 更新数据
        const totalProductsToday = productionData.real_workpiece_count ?? productionData.total_production
        this.titleItem[0].number.number[0] = totalProductsToday
        this.titleItem[1].number.number[0] = productionData.quality_products
        this.titleItem[2].number.number[0] = productionData.quality_rate
        this.titleItem[3].number.number[0] = equipmentData.equipment_rate
        this.titleItem[4].number.number[0] = equipmentData.energy_efficiency
        // 根据连接状态显示在线设备数
        this.titleItem[5].number.number[0] = this.edgeConnected ? (equipmentData.online_equipment || 1) : 0
        
        // 更新环形图数据
        this.rate[0].tips = equipmentData.equipment_rate || 87
        this.rate[1].tips = productionData.quality_rate || 95
        
        // 更新水位图
        this.water.data = [equipmentData.equipment_rate || 87, productionData.quality_rate || 95]
        this.water = { ...this.water }
        
        // 更新排行榜数据（模拟不同批次工件的良率）
        this.updateRankingData(productionData.quality_rate || 95)
        
        // 重新触发数字翻牌器更新
        this.titleItem = [...this.titleItem]
        this.rate = [...this.rate]
        
        this.loading = false
      } catch (error) {
        console.error('数据加载失败:', error)
        this.error = true
        this.loading = false
      }
    },
    updateRankingData(baseRate) {
      // 基于实际良率生成排行榜数据
      const batchNames = ['批次A', '批次B', '批次C', '批次D', '批次E', '批次F', '批次G', '批次H']
      const rankingData = batchNames.map((name, index) => {
        // 生成围绕基准良率波动的数据
        const variance = (Math.random() - 0.5) * 10
        const value = Math.max(70, Math.min(100, baseRate + variance - index * 2))
        return {
          name: name,
          value: parseFloat(value.toFixed(1))
        }
      }).sort((a, b) => b.value - a.value)
      
      this.ranking.data = rankingData
      this.ranking = { ...this.ranking }
    }
  }
}
</script>

